/**
 * If the filter field value contains position operators, the statement's operator node
 * needs to reflect them accordingly ((not) starts-with, ends-with, contains).
 * Errors are generated for invalid combinations of operators and position operators.
 */
function convertPositionOperators(
  convertedStatement: FilterFieldStatementNode,
  internalValidatorMap: InternalValidatorMap | undefined,
  positionOperators: PositionOperators,
  errors: FilterFieldError[],
  parserConfig?: FilterFieldProps['parserConfig'],
) {
  if (!convertedStatement.comparisonOperator || !positionOperators) {
    return;
  }

  const operator = convertedStatement.comparisonOperator;
  const value = operator?.value;

  if (value === '=' || value === '!=' || operator?.type === 'SearchOperator') {
    const newValue = `${value === '!=' ? 'not-' : ''}${positionOperators.type}`;
    if (convertedStatement.comparisonOperator) {
      convertedStatement.comparisonOperator.value = newValue;
    }

    // Check if position operators are limited by the validatorMap and generate errors if need be.
    if (
      !isValidOperator(
        newValue,
        convertedStatement.key?.textValue,
        internalValidatorMap,
        parserConfig,
      )
    ) {
      convertToErrorNode(convertedStatement.value);
      for (const positionOperator of positionOperators.ranges) {
        errors.push({
          range: positionOperator,
          message: 'invalidWildCardOperator',
        });
      }
    }
  } else {
    convertToErrorNode(convertedStatement.value);

    for (const positionOperator of positionOperators.ranges) {
      errors.push({
        range: positionOperator,
        message: 'invalidPositionOperator',
      });
    }
  }
}

/**
 * Validate the key and value of a filter field statement
 * according to the provided validatorMap.
 */
function validateKeyAndValue(
  internalValidatorMap: InternalValidatorMap | undefined,
  convertedStatement: FilterFieldStatementNode,
  doc: string,
  errors: FilterFieldError[],
  customTypes?: FilterFieldCustomTypes,
  parserConfig?: FilterFieldProps['parserConfig'],
) {
  if (
    !internalValidatorMap ||
    internalValidatorMap.normalizedKeys.byKey.size === 0 ||
    !convertedStatement.key
  ) {
    return;
  }

  if (convertedStatement.key.type !== 'Error') {
    validateKey(convertedStatement.key, internalValidatorMap, errors);
  }

  if (!convertedStatement.value) {
    return;
  }

  // Check each validity of each value for lists
  if (Array.isArray(convertedStatement.value.value)) {
    for (const value of convertedStatement.value.value) {
      validateSingleValue(
        value,
        doc,
        { ...convertedStatement, value },
        internalValidatorMap,
        errors,
        customTypes,
        parserConfig,
      );
    }
  } else {
    const isValid = validateSingleValue(
      convertedStatement.value,
      doc,
      convertedStatement,
      internalValidatorMap,
      errors,
      customTypes,
      parserConfig,
    );

    if (!isValid) {
      // If the value is an error, we also need to update the statement's operator node.
      // It may have changed to 'contains' or similar already, but should not reflect
      // position operators in case the value is an error.
      if (convertedStatement.comparisonOperator) {
        convertedStatement.comparisonOperator.value =
          convertedStatement.comparisonOperator.textValue;
      }
    }
  }
}

/**
 * Validate a single value of a filter field statement
 * according to the provided validatorMap.
 */
function validateSingleValue(
  value: FilterFieldStatementNode['value'],
  doc: string,
  convertedStatement: FilterFieldStatementNode,
  internalValidatorMap?: InternalValidatorMap,
  errors: FilterFieldError[] = [],
  customTypes?: FilterFieldCustomTypes,
  parserConfig?: FilterFieldProps['parserConfig'],
): boolean {
  if (!value || !convertedStatement.key) {
    return true;
  }

  const { isValid, message, validTypes } = isValidValue(
    convertedStatement.key.value,
    value.type === 'String' ? value.value : value.textValue,
    value.type,
    internalValidatorMap,
    convertedStatement,
    doc.toString(),
    customTypes,
    parserConfig,
  );

  if (!isValid) {
    convertToErrorNode(value);
    if (!validTypes || validTypes.length === 1) {
      const singleType = validTypes ? validTypes[0] : undefined;
      if (singleType && isCustomType(singleType)) {
        errors.push({
          range: value.range,
          message: message ?? {
            type: 'invalidValueErrorMultipleTypes',
            details: validTypes,
          },
        });
      } else {
        errors.push({
          range: value.range,
          message: message ?? getErrorMessageForType(singleType),
        });
      }
    } else {
      errors.push({
        range: value.range,
        message: message ?? {
          type: 'invalidValueErrorMultipleTypes',
          details: validTypes,
        },
      });
    }
  }

  return isValid;
}

/**
 * Validate a key of a filter field statement
 * according to the provided validatorMap.
 */
function validateKey(
  key: FilterFieldStatementNode['key'],
  internalValidatorMap?: InternalValidatorMap,
  errors: FilterFieldError[] = [],
) {
  if (!internalValidatorMap || !key) {
    return;
  }

  const isExhaustive = internalValidatorMap.exhaustive ?? true;
  let { value } = key;

  let isValidJsonPath = true;

  if (key.type === 'JSONPath') {
    value = key.root;

    isValidJsonPath = hasJSONPathTypePredicate(internalValidatorMap, value);
  }

  const keyIsInValidatorMap =
    internalValidatorMap.normalizedKeys.byKey.has(value);

  if ((!keyIsInValidatorMap || !isValidJsonPath) && isExhaustive) {
    convertToErrorNode(key);
    errors.push({
      range: key.range,
      message: 'invalidKey',
    });
  }
}

/**
 * Convert a filter field statement node.
 * @internal
 */
export function convertFilterStatement(
  node: SyntaxNodeRef,
  doc: string,
  numberParser: NumberFormatParser,
  internalValidatorMap: InternalValidatorMap | undefined,
  customTypes?: FilterFieldCustomTypes,
  parserConfig?: FilterFieldProps['parserConfig'],
  context?: FilterFieldLezerNodeType,
): ConvertedLezerNode<FilterFieldStatementNode> {
  const nodeName = node.name as FilterFieldLezerNodeType;
  const { from, to } = node;
  const cursor = node.node.cursor();

  const convertedStatement: FilterFieldStatementNode = {
    type: (nodeTypeOverrides[nodeName] ??
      nodeName) as FilterFieldStatementNode['type'],
    range: {
      from,
      to,
    },
  };
  const errors: FilterFieldError[] = [];
  let positionOperators: PositionOperators | undefined;
  let prevNode: FilterFieldLezerNodeType | undefined;

  /**
   * Update the previous node and return false to not go any deeper when iterating.
   * Iteration continues with the next sibling, if any.
   */
  function updatePreviousAndContinue(
    nodeName: FilterFieldLezerNodeType | undefined,
  ): false {
    prevNode = nodeName;
    return false;
  }

  cursor.iterate((childNode) => {
    const nodeName = childNode.name as FilterFieldLezerNodeType;
    const { from: childFrom, to: childTo } = childNode;

    switch (nodeName) {
      case 'FilterStatement': {
        // Intentionally left empty.
        // Duplicating the tree cursor starts at the statement node again.
        break;
      }
      case 'FilterKey': {
        const { convertedNode: filterKey, errors: keyErrors } =
          convertFilterKey(childNode, doc, parserConfig);
        if (filterKey !== undefined) {
          convertedStatement.key = filterKey;
        }
        errors.push(...keyErrors);
        return updatePreviousAndContinue(nodeName);
      }
      case 'InvalidComparisonOperator':
      case 'ComparisonOperator':
      case 'InclusionOperator': {
        const { convertedNode: operator } = convertComparisonOperator(
          childNode,
          doc,
        );
        convertedStatement.comparisonOperator = operator;
        return updatePreviousAndContinue(nodeName);
      }
      case 'SearchOperator': {
        const { convertedNode: operator, errors: operatorErrors } =
          convertSearchOperator(childNode, doc, parserConfig, context);
        convertedStatement.comparisonOperator = operator;
        errors.push(...operatorErrors);
        break;
      }
      case 'ExistsOperator': {
        const { convertedNode: operator } = convertExistsOperator(
          childNode,
          doc,
        );
        convertedStatement.comparisonOperator = operator;
        break;
      }
      case 'FilterSimpleValue': {
        const {
          convertedNode: value,
          errors: valueErrors,
          positionOperators: valuePositionOperators,
        } = convertSimpleValue(
          childNode,
          doc,
          numberParser,
          customTypes,
          parserConfig,
        );

        convertedStatement.value = value;
        errors.push(...valueErrors);
        positionOperators = valuePositionOperators;
        return updatePreviousAndContinue(nodeName);
      }
      case 'FilterIncludesValue': {
        const { convertedNode: value, errors: valueErrors } =
          convertInclusionValue(
            childNode,
            doc,
            numberParser,
            customTypes,
            parserConfig,
          );
        convertedStatement.value = value;
        errors.push(...valueErrors);
        return updatePreviousAndContinue(nodeName);
      }
      case 'FreeText': {
        const { convertedNode: freeTextNode, errors: freeTextErrors } =
          convertFreeText(childNode, doc, parserConfig);
        convertedStatement.key = freeTextNode;
        errors.push(...freeTextErrors);
        return updatePreviousAndContinue(nodeName);
      }
      // An error node may occur as direct child of a 'FilterStatement'.
      // Depending on the context, it needs to be added to the corresponding node (key, comparator, or value).
      case '⚠':
        switch (prevNode) {
          case 'FilterKey':
          case 'FreeText':
            // eslint-disable-next-line @typescript-eslint/no-deprecated
            if (parserConfig?.searchConversion) {
              errors.push({
                range: { from: childFrom - 1, to: childTo },
                message: {
                  type: 'incompleteStatementWithEnabledSearchError',
                  details: getColoredSearchOperator(),
                },
                decoration: postSpotErrorMark,
              });
            } else {
              errors.push({
                range: { from: childFrom - 1, to: childTo },
                message: 'incompleteStatementError',
                decoration: postSpotErrorMark,
              });
            }
            break;
          case 'ComparisonOperator':
          case 'InvalidComparisonOperator':
          case 'SearchOperator':
            if (convertedStatement.comparisonOperator !== undefined) {
              if (childFrom !== childTo) {
                const childAfter = childNode.node.nextSibling;
                if (childAfter) {
                  // Update range.to for both if they exist
                  if (convertedStatement.comparisonOperator) {
                    convertedStatement.comparisonOperator.range.to = childTo;
                    const textValue = getTextFromRange(
                      convertedStatement.comparisonOperator.range,
                      doc,
                    );
                    convertedStatement.comparisonOperator.textValue =
                      convertedStatement.comparisonOperator.value = textValue;
                  }
                  return updatePreviousAndContinue(prevNode);
                } else {
                  const range = {
                    from: childFrom,
                    to: childTo,
                  };

                  const textValue = getTextFromRange(range, doc);

                  convertedStatement.value = {
                    type: 'Error',
                    value: textValue,
                    textValue,
                    range,
                  };

                  errors.push({
                    range,
                    message: 'invalidValueErrorGeneric',
                  });
                }
              } else {
                errors.push({
                  range: {
                    from: childFrom - (childFrom === childTo ? 1 : 0),
                    to: childTo,
                  },
                  message: 'missingValueError',
                  decoration: postSpotErrorMark,
                });
              }
            }
            break;
          case 'InclusionOperator':
            errors.push({
              range: { from: childFrom - 1, to: childTo },
              message: 'missingValueError',
            });
            break;
          default:
            if (isDev()) {
              // eslint-disable-next-line no-console
              console.log(
                `${doc.toString()} | Syntax node '${nodeName}' is not yet handled after a '${prevNode}' node. Please make sure to handle all nodes accordingly.`,
              );
            }
        }

        return updatePreviousAndContinue(nodeName);
      default:
        // eslint-disable-next-line no-console
        console.log(
          `${doc.toString()} | Syntax node '${nodeName}' is not yet handled in the statement conversion. Please make sure to handle all nodes accordingly.`,
        );
    }

    prevNode = nodeName;
  });

  if (convertedStatement.comparisonOperator && positionOperators) {
    convertPositionOperators(
      convertedStatement,
      internalValidatorMap,
      positionOperators,
      errors,
      parserConfig,
    );
  }

  /**
   * Custom validation
   */
  validateKeyAndValue(
    internalValidatorMap,
    convertedStatement,
    doc,
    errors,
    customTypes,
    parserConfig,
  );

  // Check the validity of the operator node, regardless of whether there
  // is a validatorMap, as there are default global operators.
  const operator = convertedStatement.comparisonOperator;
  if (
    operator &&
    !positionOperators &&
    (!isValidOperator(
      operator.textValue,
      convertedStatement.key?.value,
      internalValidatorMap,
      parserConfig,
    ) ||
      (operator.type === 'Error' && operator.value !== '*~'))
  ) {
    convertToErrorNode(operator);

    if (convertedStatement.comparisonOperator) {
      convertToErrorNode(convertedStatement.comparisonOperator);
    }
    errors.push({
      range: operator.range,
      message: {
        type: 'invalidComparatorError',
        details: getValidOperatorsColored(
          convertedStatement.key?.textValue,
          internalValidatorMap,
          parserConfig,
        ),
      },
    });
  }

  return { convertedNode: convertedStatement, errors };
}

function hasJSONPathTypePredicate(
  internalValidatorMap: InternalValidatorMap,
  key: string,
): boolean {
  const config = internalValidatorMap.normalizedKeys.byKey.get(key);

  if (!config) {
    return false;
  }

  if (config.valueType) {
    const types = Array.isArray(config.valueType)
      ? config.valueType
      : [config.valueType];
    return types.includes('JSONPath');
  }

  const validValues = config.valuePredicate;

  if (!validValues || typeof validValues === 'function') {
    return false;
  }

  const { types: validTypes } = getValidValueTypes(validValues);

  return validTypes.includes('JSONPath');
}
